class Solution {
    public int minimumLength(String s) {
        int length = s.length();
        int result = length;

        for (int i = 0; i < length; i++) {
            for (int j = i + 1; j < length; j++) {
                if (s.charAt(i) == s.charAt(j)) {
                    result = Math.min(result, length - i - j);
                }
            }
        }
        return result;
    }
}
```

